"use client";

import { useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { ChevronRight, Clock, Users } from "lucide-react";
import { allCourses, Course } from "@/data/all_courses";
import CourseFilter from "@/components/courses/CourseFilter";

export default function CoursesPage() {
  const [filteredCourses, setFilteredCourses] = useState<Course[]>(allCourses);

  const handleFilterChange = (category: string, duration: string) => {
    let results = allCourses;
    if (category !== "all") {
      results = results.filter((c) => c.category === category);
    }
    if (duration !== "all") {
      results = results.filter((c) => c.duration === duration);
    }
    setFilteredCourses(results);
  };

  return (
    <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Breadcrumb */}
      <nav className="flex items-center gap-2 text-sm font-medium text-slate-500 mb-8">
        <Link href="/" className="hover:text-primary transition-colors">
          Home
        </Link>
        <ChevronRight className="w-4 h-4" />
        <span className="text-slate-900">Courses</span>
      </nav>

      {/* Header Section */}
      <div className="mb-12">
        <h1 className="text-5xl font-black text-slate-900 mb-2">Courses</h1>
        <p className="text-lg text-slate-600">Popular Courses at Orphosys</p>
      </div>

      <CourseFilter onFilterChange={handleFilterChange} />

      {/* Course Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-20 min-h-[400px]">
        {filteredCourses.length > 0 ? (
          filteredCourses.map((course) => (
            <div
              key={course.id}
              className="group bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm hover:shadow-xl transition-all duration-500"
            >
              <div className="relative h-56 overflow-hidden">
                <Image
                  src={course.image}
                  alt={course.title}
                  fill
                  className="object-cover group-hover:scale-105 transition-transform duration-500"
                />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full text-xs font-bold text-primary">
                  {course.category}
                </div>
              </div>
              <div className="p-6">
                <h3 className="text-xl font-bold text-slate-900 group-hover:text-primary transition-colors mb-4">
                  {course.title}
                </h3>
                <div className="flex items-center gap-4 text-slate-500 text-sm mb-6">
                  <div className="flex items-center gap-1.5">
                    <Clock className="w-4 h-4" />
                    {course.duration}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Users className="w-4 h-4" />
                    {course.studentCount}
                  </div>
                </div>
                <button className="w-full py-3 bg-slate-50 text-slate-900 font-bold rounded-xl hover:bg-primary hover:text-white transition-all">
                  Enroll Now
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="col-span-full flex flex-col items-center justify-center py-20 text-slate-500">
            <span className="material-symbols-outlined text-6xl mb-4">search_off</span>
            <p className="text-xl font-semibold">No courses found matching your filters.</p>
            <button 
              onClick={() => handleFilterChange("all", "all")}
              className="mt-4 text-primary font-bold hover:underline"
            >
              Clear all filters
            </button>
          </div>
        )}
      </div>
    </main>
  );
}
